#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
private:
    vector<vector<int>> res;
    void backtrack(vector<int>& candidates, int target, int start, vector<int>& path) {
        if (target == 0) {
            res.push_back(path);
            return;
        }
        for (int i = start; i < candidates.size(); i++) {
            if (i > start && candidates[i] == candidates[i - 1]) continue;
            if (candidates[i] > target) break;
            path.push_back(candidates[i]);
            backtrack(candidates, target - candidates[i], i + 1, path);
            path.pop_back();
        }
    }

public:
    vector<vector<int>> combinationSum2(vector<int>& candidates, int target) {
        sort(candidates.begin(), candidates.end());
        res.clear();
        vector<int> path;
        backtrack(candidates, target, 0, path);
        return res;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> candidates(n);
    for (int i = 0; i < n; i++) cin >> candidates[i];
    int target;
    if (!(cin >> target)) return 0;
    Solution sol;
    vector<vector<int>> ans = sol.combinationSum2(candidates, target);
    cout << ans.size() << "\n";
    for (const auto& row : ans) {
        for (int i = 0; i < row.size(); i++) {
            cout << row[i] << (i == row.size() - 1 ? "" : " ");
        }
        cout << "\n";
    }
    return 0;
}
